mapper.select:
SELECT o.id, o.company_name AS "companyName", o.legal_name AS "legalName",
       o.gst_number AS "gstNumber", o.pan_number AS "panNumber", o.domain,
       o.active, o.created_time AS "createdAt"
FROM organisation o

  AND o.id = #{id}
  AND LOWER(o.company_name) LIKE LOWER(CONCAT('%', #{companyName}, '%'))
  AND o.active = #{active}
  AND o.domain = #{domain}

ORDER BY o.created_time DESC

SELECT COUNT(*) FROM organisation o

  AND o.id = #{id}
  AND LOWER(o.company_name) LIKE LOWER(CONCAT('%', #{companyName}, '%'))
  AND o.active = #{active}
